#include <stdio.h>

int main(void) {
    int numbers[10];
    char pick;
    int score = 0;

    // Initialize numbers array with random values (for demonstration purposes)
    for (int i = 0; i < 10; i++) {
        numbers[i] = rand() % 20 + 1;
    }

    printf("Numbers: ");
    for (int i = 0; i < 10; i++) {
        printf("%d ", numbers[i]);
    }
    printf("\n");

    while (scanf(" %c", &pick) == 1) {
        if (pick == 'O' || pick == 'E') {
            int number;
            scanf("%d", &number);

            if ((numbers[number - 1] % 2 == 0 && pick == 'E') ||
                (numbers[number - 1] % 2 != 0 && pick == 'O')) {
                score++;
                printf("Correct! Points: %d\n", score);
            } else {
                printf("Wrong! Points: %d\n", score);
            }
        } else {
            printf("Invalid input. Please enter 'O' or 'E'.\n");
        }
    }

    return 0;
}

#include <stdio.h>

int main(void) {
    int rounds;
    scanf("%d", &rounds);

    int playerScore = 0;
    int computerScore = 0;

    for (int i = 0; i < rounds; i++) {
        int playerChoice, computerChoice;

        printf("Round %d:\n", i + 1);
        printf("Enter your choice (1: Rock, 2: Paper, 3: Scissors): ");
        scanf("%d", &playerChoice);

        // Generate random number for computer's choice
        computerChoice = rand() % 3 + 1;

        printf("Computer chose: %d\n", computerChoice);

        int result = playerChoice - computerChoice;
        if (result == 0) {
            printf("It's a tie!\n");
        } else if ((result == 1) || (result == -2)) {
            playerScore++;
            printf("You win this round!\n");
        } else {
            computerScore++;
            printf("Computer wins this round!\n");
        }

        printf("Current score: Player %d, Computer %d\n", playerScore, computerScore);
    }

    if (playerScore > computerScore) {
        printf("Congratulations! You win the game.\n");
    } else if (computerScore > playerScore) {
        printf("Computer wins the game. Better luck next time!\n");
    } else {
        printf("It's a tie game!\n");
    }

    return 0;
}

#include <stdio.h>
#include <math.h>

int main(void) {
    double x[4], y[4];
    for (int i = 0; i < 4; i++) scanf("%lf %lf", &x[i], &y[i]);

    // Calculate the lengths of the sides of the triangle
    double a = sqrt(pow(x[1] - x[0], 2) + pow(y[1] - y[0], 2));
    double b = sqrt(pow(x[2] - x[1], 2) + pow(y[2] - y[1], 2));
    double c = sqrt(pow(x[3] - x[2], 2) + pow(y[3] - y[2], 2));

    // Calculate the semi-perimeter
    double s = (a + b + c) / 2.0;

    // Calculate the area using Heron's formula
    area = sqrt(s * (s - a) * (s - b) * (s - c));

    printf("area %.3f\n", area);
    return 0;
}

