#include <stdio.h>

int main(void) {
    int n;
    double sum = 0.0;

    // Read input
    scanf("%d", &n);

    // Compute harmonic-style signed sum
    for (int i = 1; i <= n; i++) {
        sum += pow(-1, i) * i / (2 * i + 1);
    }

    // Print the final sum with a label and 3 decimal places
    printf("result: %.3f\n", sum);

    return 0;
}

